<template>
    <section class="main-content">
        <loader :is-visible="isLoading"></loader>

        <div class="padding-t_10 p-0" id="reportstabsdata">
            <!-- LEFT MENU -->
            <div class="left-menu-tab mt-2">
                <div class="col-md-12 p-0">
                    <div class="theme-primary partition">
                        <span class="p-name text-white">{{ $t("BillingRule") }}</span>
                    </div>
                </div>

                <ul class="nav nav-pills flex-column left-tab mt-2 responivecustomtab nav-tabs">
                    <li
                        v-for="tab in tabs"
                        :key="tab.id"
                        @click="changeTab(tab)"
                        :class="{
                            'nav-item': true,
                            'active': currentTab.title === tab.title,
                            'disabled-tab': !tabsUnlocked && tab.title !== $t('BillingRuleConfiguration')
                        }"
                        :style="!tabsUnlocked && tab.title !== $t('BillingRuleConfiguration')
                            ? 'pointer-events:none;opacity:0.5;'
                            : ''"
                    >
                        <span
                            :class="{
                                'nav-link left-menu': true,
                                'active': currentTab.title === tab.title
                            }"
                        >
                            <i :class="tab.icon" class="p-1"></i>
                            {{ tab.displayName }}
                        </span>
                    </li>
                </ul>
            </div>

            <!-- RIGHT CONTENT -->
            <div class="right-content tablehead">
                <div class="tab-content z-indexfix">
                    <div class="expand-list">
                        <a href="javascript:;" class="expand-list-btn">
                            <i class="icon-solid arrow-solid-left text-white"></i>
                        </a>
                    </div>

                    <!-- Normal header when not unauthorized and not on Limit tab -->
                    <div
                        class="theme-primary partition p-actions-expand mt-2"
                        v-if="!isUnauthorized && currentTab.title !== $t('LimitValue')"
                    >
                        <span class="p-name text-white">{{ billingRule }}</span>

                        <RouterLink
                            v-if="reqType !== 'fromServiceMapping'"
                            :to="isBillingType ? '/BillingRule/RuleListing' : '/BillingRule/Index'"
                            class="p-actions float-md-right float-left mb-wid-100"
                        >
                            <span class="p-action-btn text-white d-none d-md-inline-block">
                                <em aria-hidden="true" class="fa fa-angle-double-left"></em>
                                <br>{{ $t('Back') }}
                            </span>
                        </RouterLink>
                        <a v-if="isBillingType && mode == 'Edit' && currentTab.title !== $t('BillingRuleConfiguration')"  @click="callSaveServiceRules" class="p-action-btn text-white float-right" :title="$t('Save')">
                            <em class="fa fa-save"></em><br>
                            {{ $t("Save") }}
                        </a>
                        <a v-if="isBillingType && mode == 'Edit' && currentTab.title == $t('NodeConfiguration')" @click="callAddMoreRule" class="p-action-btn text-white float-right" :title="$t('AddMoreRule')">
                            <em class="fa fa-plus"></em><br>
                            {{ $t("AddMoreRule") }}
                        </a>
                        <a v-if="isBillingType && (mode == 'View'  || mode == 'Edit') && currentTab.title == $t('FlowChart1')" @click="callPrintVerticalFlow" 
                              class="p-action-btn text-white float-right" :title="$t('Print')">
                            <em class="fa fa-print"></em><br>
                            {{ $t("Print") }}
                        </a>
                        <a v-if="isBillingType && mode == 'View'" @click="EditRuleService" class="p-action-btn text-white float-right" :title="$t('Edit')">
                            <em class="fa fa-pencil"></em><br>
                            {{ $t("Edit") }}
                        </a>
                        <a v-if="currentTab.title === $t('OverrideCharge') && mode !== 'View'" @click="callAddNew"
                            class="p-action-btn text-white float-right" :title="$t('Add')">
                            <em class="fa fa-plus"></em><br>
                            {{ $t("Add") }}
                        </a>
                    </div>

                    <!-- Header when unauthorized on any protected tab: only show Back button -->
                    <div
                        class="theme-primary partition p-actions-expand mt-2"
                        v-else-if="isUnauthorized"
                    >
                        <span class="p-name text-white">{{  billingRule }}</span>

                        <RouterLink
                            v-if="reqType !== 'fromServiceMapping'"
                            :to="isBillingType ? '/BillingRule/RuleListing' : '/BillingRule/Index'"
                            class="p-actions float-md-right float-left mb-wid-100"
                        >
                            <span class="p-action-btn text-white d-none d-md-inline-block">
                                <em aria-hidden="true" class="fa fa-angle-double-left"></em>
                                <br>{{ $t('Back') }}
                            </span>
                        </RouterLink>
                    </div>

                    <div 
                    :class="[
                            'col-md-12',
                            { 
                            border: currentTab.title !== $t('LimitValue'),
                            'float-left': currentTab.title !== $t('LimitValue')
                            }
                        ]" v-if="!isUnauthorized"
                    
                    >
                        <BillingRuleConfiguration
                            v-if="currentTab.title === $t('BillingRuleConfiguration')"
                            :configurationId="configurationId"
                            :serviceId="serviceId"
                            :reqType="reqType"
                            :isBillingType="isBillingType"
                            @config-saved="handleSavedConfig"
                        />

                        <NodeConfiguration
                            v-show="currentTab.title === $t('NodeConfiguration')"
                            :configurationId="configurationId"
                            ref="nodeConfigRef"
                            :serviceId="serviceId"
                            :reqType="reqType"
                            :mode="mode"
                            :isBillingType="isBillingType"
                            :clientId="clientId"
                            :setupId="setupId"
                            @unsaved-state-changed="handleNodeUnsavedChanged"
                        />

                        <Limit
                            v-if="currentTab.title === $t('LimitValue')"
                            :configurationId="configurationId"
                            :mode="mode"
                            ref="limitRef"
                            :isBillingType="isBillingType"
                            @edit-configuration="EditRuleService"
                            @save_configuration="callSaveServiceRules"
                            :clientId="clientId" 
                            :billingRule="billingRule"
                        />
                        <OverrideCharges
                            v-if="currentTab.title === $t('OverrideCharge')"
                            ref="overrideChargesRef"
                            :configurationId="configurationId"
                            :mode="mode"
                            :isBillingType="isBillingType"
                            :clientId="clientId"
                        />

                        <VerticalFlowChart
                            v-if="currentTab.title === $t('FlowChart1')"
                            :configurationId="configurationId" ref="verticalFlowRef"
                            :isBillingType="isBillingType" :clientId="clientId"
                        />

                        <HorizontalFlowChart
                            v-if="currentTab.title === $t('FlowChart')"
                            :configurationId="configurationId"
                            :isBillingType="isBillingType"
                        />
                    </div>
                    <div class="col-md-12 p-0" v-else-if="isUnauthorized">
                        <Unauthorized />
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import DataServices from "../../services/DataService";
import BillingRuleConfiguration from "./ConfigurationComponent/BillingRuleConfiguration.vue";
import Limit from "./ConfigurationComponent/Limit.vue";
import NodeConfiguration from "./ConfigurationComponent/NodeConfiguration.vue";
import VerticalFlowChart from "./ConfigurationComponent/VerticalFlowChart.vue";
import OverrideCharges from "./ConfigurationComponent/OverrideCharges.vue";
import HorizontalFlowChart from "./ConfigurationComponent/HorizontalFlowChart.vue";
import Unauthorized from '../auth/Unauthorized.vue';
import {
    locateBillingService
} from "../../services/locateBillingService";
import { moduleStore } from "../../stores/UserInfo";

export default {
    components: {
        BillingRuleConfiguration,
        Limit,
        NodeConfiguration,
        VerticalFlowChart,
        OverrideCharges,
        HorizontalFlowChart,
        Unauthorized
    },

    props: {
        serviceId: {
            type: Number,
            required: false
        },
        reqType: {
            type: String,
            required: false
        },
        configurationId: {
            type: Number,
            required: false
        },
        mode: { 
            type: String, 
            required: false
        }
    },

    data() {
        return {
            isLimitEditMode: false,
            tabsUnlocked: false,
            isLoading: false,
            isBillingType: false,
            // configurationId: 0,
            // clientId: 0,
            isUnauthorized:false,
            mode: "Edit",
            billingRule:'',
            tabs: [
                { id: 1, title: this.$t("BillingRuleConfiguration"), displayName: this.$t("BillingRuleConfiguration"), icon: "fa fa-cogs" },
                { id: 2, title: this.$t("NodeConfiguration"), displayName: this.$t("NodeConfiguration"), icon: "fa fa-xing" },
                { id: 3, title: this.$t("LimitValue"), displayName: this.$t("LimitValue"), icon: "fa fa-circle-o-notch" },
                { id: 4, title: this.$t("OverrideCharge"), displayName: this.$t("OverrideCharge"), icon: "fa fa-deviantart" },
                { id: 5, title: this.$t("FlowChart1"), displayName: this.$t("FlowChart1"), icon: "fa fa-usb" },
                { id: 6, title: this.$t("FlowChart"), displayName: this.$t("FlowChart"), icon: "fa fa-sitemap" }
            ],

            currentTab: null,
            setupId:32,
            hasUnsavedNodeChanges: false
        };
    },

    async created() {
        this.isBillingType = localStorage.getItem("billingType") === "USIC";
        this.mode = this.$route.params.mode || "Edit";
        this.configurationId = parseInt(this.$route.params.id);
        this.serviceId = parseInt(this.$route.params.serviceId);
        if (this.configurationId) {
            this.tabsUnlocked = true;
            if (this.isBillingType) {
                await this.BindConfigurationData();
            }
        }

        this.currentTab =
            this.mode === "View" || this.mode === "Edit"
                ? this.tabs.find(t => t.title === this.$t("NodeConfiguration"))
                : this.tabs[0];
    },

    mounted() {
        window.addEventListener("beforeunload", this.handleBeforeUnload);
    },

    beforeDestroy() {
        window.removeEventListener("beforeunload", this.handleBeforeUnload);
    },

   watch: {
        "$route.params.id": async function (newId) {
            if (newId && this.isBillingType) {
                this.configurationId = parseInt(newId);

                await this.BindConfigurationData();
            }
        },

        "$route.params.mode": function (newMode) {
            this.mode = newMode || "Edit";
        },
        currentTab: {
            handler(newTab) {
            if (newTab) {
                this.updateUserGuide(newTab);
            }
            },
            immediate: true
        }
    },

    beforeRouteLeave(to, from, next) {
        if (this.mode === "Edit" && this.hasUnsavedNodeChanges) {
            const leave = window.confirm("Changes you made may not be saved.");

            if (leave) {
                this.hasUnsavedNodeChanges = false;
                next();
            } else {
                next(false);
            }
        } else {
            next();
        }
    },

    methods: {
    updateUserGuide(tab) {
            if (!tab) return;
            let guide = '';
            if (tab.title === this.$t('NodeConfiguration')) {
            guide = 'User_Guide_Billing_Rule_Node_Configuration';
            } else if (tab.title === this.$t('OverrideCharge')) {
            guide = 'User_Guide_Billing_Rule_Override_charges';
            } else if (tab.title === this.$t('FlowChart1')) {
            guide = 'User_Guide_Billing_Rule_Node_Vertical_Flow_Chart';
            } else if (tab.title === this.$t('FlowChart')) {
            guide = 'User_Guide_Billing_Rule_Node_Flow_Chart';
            } else if (tab.title === this.$t('BillingRuleConfiguration')) {
            guide = 'User_Guide_Billing_Rule_Node'; 
            } else if (tab.title === this.$t('LimitValue')) {
            guide = ''; 
            }
            
            // Use Pinia store to update userguide
            const store = moduleStore();
            store.SetUserGuide(guide);
        },
        handleBeforeUnload(event) {
            if (this.mode === "Edit" && this.hasUnsavedNodeChanges) {
                event.preventDefault();
                event.returnValue = "";
            }
        },

        handleNodeUnsavedChanged(isDirty) {
            this.hasUnsavedNodeChanges = this.mode === "Edit" && !!isDirty;
        },

        callPrintVerticalFlow(){
            if (this.$refs.verticalFlowRef) {
                this.$refs.verticalFlowRef.printPage();
            }
        },
        callSaveServiceRules(){
            // Always delegate saving to NodeConfiguration (rules + display order),
            // even when Save is triggered from the Limit tab.
            if (this.$refs.nodeConfigRef && this.$refs.nodeConfigRef.saveServiceRules) {
                this.$refs.nodeConfigRef.saveServiceRules('TM');
            }
        },
        callAddMoreRule() {
            if (this.$refs.nodeConfigRef) {
            this.$refs.nodeConfigRef.addMoreRule();
            }
        },
        EditRuleService: async function () {
            var vm = this;
            if(this.isBillingType){
                 vm.getNodeConfiguration(this.configurationId,this.serviceId,'Edit')
            }
        },
        getNodeConfiguration: function (configId,serviceId,mode) {
            let ths = this;

            // const proceed = () => {
                var prms = `configId=${configId}&serviceId=${serviceId}&isIncludeGlobalService=true&isView=${mode}`;
                DataServices.GetNodeConfiguration(prms).then(function (res) {
                    debugger;
                    if (res?.data?.length > 0 && res.data[0]?.CONFIG_ID != null && res.data[0]?.SERVICE_ID != null) {
                        var config_Id = res.data[0].CONFIG_ID;
                        var service_Id = res.data[0].SERVICE_ID != null ? ths.serviceId : res.data[0].SERVICE_ID;
                        ths.$router.push({
                            name: 'ManageConfiguration',
                            params: { id: config_Id,serviceId: service_Id, mode: 'Edit',ocId:configId }
                        }).then(() => {
                            // window.location.reload();
                        });
                        debugger;
                        if(ths.currentTab.title == ths.$t("LimitValue")){
                            const limitTab = ths.tabs.find(t => t.title === ths.$t("LimitValue"));
                            if (limitTab) {
                                ths.currentTab = limitTab;
                            }
                        }
                       
                    }
                });
            // };

            // if (this.mode === "Edit" && this.hasUnsavedNodeChanges) {
            //     debugger;
            //     // Ask user before discarding unsaved Node Configuration data
            //     this.confirmR("Changes you made may not be saved.",
            //         true,
            //         this.$t ? this.$t("Alert") : "Alert",
            //         function () {
            //             ths.hasUnsavedNodeChanges = false;
            //             proceed();
            //         }
            //     );
            // } else {
            //     proceed();
            // }
        },
        async BindConfigurationData() {
            // if (this.clientId) return; 
            this.isLoading = true;
            const url = `configId=${this.configurationId}&isForUtilityBilling=${this.isBillingType == true ? false : true}`;
            const response = await DataServices.GetConfigurationData(url);
            if (response?.data?.length) {
                this.clientId = response.data[0].client_id;
                var billingRule = response.data[0].billing_config_name;
                this.setupId = response.data[0].setup_id
                this.BindCompanyContractClients(this.clientId,billingRule);
            }
            this.isLoading = false;
        },
        BindCompanyContractClients: async function (clientId,billingRuleName) {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            await locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                const client = vm.clientList.filter(c => c.value == clientId)[0];
                var selectedClientName = client?.text || '';
                this.billingRule = billingRuleName + '  (' + selectedClientName + ')';
               
             
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = []; 
               
               
            }).finally(() => {
                vm.isLoading = false;
            });
        },
        async changeTab(tab) {
            if (!this.tabsUnlocked && tab.title !== this.$t("BillingRuleConfiguration")) return;

            // reset unauthorized state on every tab change
            this.isUnauthorized = false;
            // Only warn when navigating specifically from Node Configuration to Billing Rule Configuration
            const isNodeToBillingRuleConfig =
                this.currentTab &&
                this.currentTab.title === this.$t("NodeConfiguration") &&
                tab.title === this.$t("BillingRuleConfiguration");

            if (this.mode === "Edit" && isNodeToBillingRuleConfig && this.hasUnsavedNodeChanges) {
                const vm = this;
                const message =
                    this.$t?.("WindowUnloadMessage");

                this.confirmR(
                    message,
                    true,
                    this.$t ? this.$t("Alert") : "Alert",
                    function () {
                        if (vm.$refs.nodeConfigRef && vm.$refs.nodeConfigRef.resetToOriginalState) {
                            vm.$refs.nodeConfigRef.resetToOriginalState();
                        }
                        vm.hasUnsavedNodeChanges = false;
                        vm.currentTab = tab;
                    }
                );
                return;
            }

            // Visually select the tab immediately
            this.currentTab = tab;

            // When clicking on Limit tab, check privilege first
            if (tab.title === this.$t("LimitValue")) {
                const param = 'controller=BillingRule&action=LimitIndex';
                const response = await DataServices.CheckPrivilege(param);

                if (!response || !response.data) {
                    this.isUnauthorized = true;
                }
            }
            // When clicking on OverrideCharge tab, check privilege as well
            else if (tab.title === this.$t("OverrideCharge")) {
                const param = 'controller=BillingRule&action=OverrideCharge';
                const response = await DataServices.CheckPrivilege(param);

                if (!response || !response.data) {
                    this.isUnauthorized = true;
                }
            }
        },

        handleSavedConfig(payload) {
            this.configurationId = payload.configId;
            this.tabsUnlocked = true;

            if (payload.goTo) {
                const nextTab = this.tabs.find(t => t.title === this.$t(payload.goTo));
                if (nextTab) this.currentTab = nextTab;
            }
        },

        callAddNew() {
            var vm = this;
            var param = 'controller=BillingRule&action=OverrideCharge';
                DataServices.CheckPrivilege(param).then(function (response) {
                    if (response.data) {
                         vm.$refs.overrideChargesRef?.AddNewRow?.();
                    }
                    else {
                        vm.ShowAlert(vm.$t("NotAuthorizedSection"), 'Warning', true, vm.$t('Alert'));
                    }
            })
        }
    }
};
</script>

<style scoped>
.disabled-tab {
    cursor: not-allowed;
}
</style>
