<template>
    <div>
        <div class="row">
          
            <div class="col-md-12 pt-0 mb-2 mt-2">
                <div class="col-sm-12 col-md-12 col-lg-6 col-xl-6 p-0">
                    <div class="mr-2 d-inline-block">
                        <span class="legend-pending colorboxsquare"></span> {{ $t("ServiceValidation") }}
                    </div>
                    <div class="mr-2 d-inline-block">
                        <span class="legend-upcoming colorboxsquare"></span> {{ $t("LeafNodeValidation") }}
                    </div>
                </div>
                <div class="heading-border mb-3">
                        <h5 class="h5"><span>{{ $t("RootNode") }}</span></h5>
                </div>
                <RecursiveNodeConfiguration :rules="rules" :name="'RecursiveNodeConfiguration'"
                    :configurationId="configurationId" :reqType="reqType" :serviceId="serviceId" :mode="mode" @rule-merged="handleRuleMerged" 
                    :isBillingType="isBillingType" :clientId="clientId" :setupId="setupId" :parentMappingId="parentMappingId" :highlightEmptyConditions="showEmptyConditionHighlight" :highlightLeafCheckedFalse="showLeafCheckedFalseHighlight"></RecursiveNodeConfiguration>
            </div>
            <div class="col-md-12 pb-2" v-if="rules.length == 0">
                <div class="border-bottom text-center text-danger p-2">
                    {{ $t("NorecordfoundText") }}
                </div>
            </div>
        </div>
       
        <div class="text-right mb-2" v-if="mode !== 'View'">
            <button type="button" class="btn btn-info mr-2" @click="addMoreRule">
                <em class="fa fa-plus"></em> {{ $t("AddMoreRule") }}
            </button>
            
            <button type="button" class="btn btn-success mr-2" @click="saveServiceRules('TM')">
                <em class="fa fa-save"></em> {{ $t("SaveRule") }}
            </button>
            <button type="button" class="btn btn-danger" @click="RuleCancel">
                <em class="fa fa-times"></em> {{ $t("Cancel") }}
            </button>
        </div>
    </div>
</template>
<script>
import DataServices from "./../../../services/DataService";
import RecursiveNodeConfiguration from "./RecursiveNodeConfiguration.vue";
export default {
    components: { "RecursiveNodeConfiguration": RecursiveNodeConfiguration },
    props: {
        configurationId: {
            type: Number,
            required: false
        },
        reqType: {
            type: String,
            default: null
        },
        serviceId:{
            type: Number,
            required: false
        },
        mode: {
            type: String,
            default: 'Edit'
        },
        isBillingType :{
            type: Boolean,
            required: false
        },
        clientId:{
            type: Number,
            required: false
        },
        setupId:{
            type: Number,
            required: false
        }
    },
    data: function () {
        return {
            rules: [],
            jsonToSaveRules: [],
            processedData: [],
            nodeList:[],
            oldConfigId:0,
            nodeRuleData:[],
            parentMappingId:0,
            originalRules: [],
            hasInitialRulesSnapshot: false,
            showEmptyConditionHighlight: false,
            showLeafCheckedFalseHighlight:false,
            hasValidationActivity: false
        }
    },
    created: async function () {
        this.serviceId = this.reqType === 'fromServiceMapping' ? this.serviceId : parseInt(this.$route.params.serviceId);  
        this.oldConfigId = this.$route.params.ocId;
        await this.BindConfigurationData();
        this.GetNodeConfigurationData();
    },

    watch: {
        rules: {
            handler(newVal) {
                if (!this.hasInitialRulesSnapshot) return;
                try {
                    const current = JSON.stringify(newVal || []);
                    const original = JSON.stringify(this.originalRules || []);
                    const isDirty = current !== original;
                    this.$emit("unsaved-state-changed", isDirty);
                } catch (e) {
                    // Fallback: on serialization error, assume dirty
                    this.$emit("unsaved-state-changed", true);
                }
            },
            deep: true
        }
    },
    methods: {
        resetToOriginalState() {
            try {
                this.rules = JSON.parse(JSON.stringify(this.originalRules || []));
                this.$emit("unsaved-state-changed", false);
            } catch (e) {
                this.$emit("unsaved-state-changed", false);
            }
        },
        BindConfigurationData: async function (configurationId) {
            var vm = this;
            const url = `configId=${this.configurationId}&isForUtilityBilling=${this.isBillingType == true ? false : true}`;
            const response = await DataServices.GetConfigurationData(url);
            if (response && response.data && response.data.length > 0) {
                vm.parentMappingId = response.data[0].client_service_mapping_id;
            }
        },
        RuleCancel:function() {
            var vm = this;
            if(vm.reqType == 'fromServiceMapping'){
                this.$parent.$parent.$parent.isModalBillingConfiguration=false;
                this.$parent.$parent.$parent.FetchData();
            }
            else
            {
                vm.$router.push({name: vm.isBillingType ? 'BillingRule' : 'BillingRuleListing'});
            }
        },
        handleRuleMerged(ruleList) {
            debugger;
            this.rules = ruleList;
            this.hasValidationActivity = true;
        },
        makeJsonForSave: function (rule) {
            let ths = this;
            var isUpdate = false;
            if (rule.ruleCondition.hasOwnProperty('isUpdateRule')) {
                isUpdate = rule.ruleCondition.isUpdateRule;
            }
            var objRule = {
                ruleId: rule.ruleId,
                ruleDisplayOrder: rule.ruleDisplayOrder,
                ruleName: rule.ruleName,
                conditionId: rule.ruleCondition.conditionId,
                rateCodeId: rule.ruleCondition.rateCode,
                parentServiceId : Number(rule.ruleId) == 0 ? this.serviceId : rule.ruleCondition.parentServiceId,
                parentMappingId : Number(rule.ruleId) == 0 ? this.parentMappingId : rule.ruleCondition.parentMappingId,
                isLeafChecked: rule.ruleCondition.isLeafChecked,
                usageBased: rule.ruleCondition.addAdder,
                usageBasedSlabs: rule.ruleCondition.adderRows,
                usageBasedType: rule.ruleCondition.adderType,
                selectedflag: rule.ruleCondition.selectedFlag.value,
                version: rule.version,
                parent: rule.version,
                isDelete: rule.isDelete,
                isUpdateRule: isUpdate,
                dependentOnServices: rule.ruleCondition.dependentOnServices,
                dependentPrice: rule.ruleCondition.dependentPrice,
                dependentType: rule.ruleCondition.dependentType,
                functionType: rule.ruleCondition.functionType

            }
            this.jsonToSaveRules.push(objRule);
            rule.rules.forEach(function (itm, index) {
                ths.makeJsonForSave(itm);
            });
        },
        saveServiceRules: function (type) {
            debugger
            let ths = this;
            
            const hasEmptyCondition = this.rules.some(rule => 
                rule.ruleCondition && Object.keys(rule.ruleCondition).length === 0
            );
            
            this.hasValidationActivity = hasEmptyCondition;
            
            if (this.hasValidationActivity) {
                const hasEmptyConditionCheck = this.checkEmptyCondition(this.rules);
                const hasLeafCheckedFalse = this.checkLeafCheckedFalse(this.rules);
                
                if (hasEmptyConditionCheck || hasLeafCheckedFalse) {
                    this.showEmptyConditionHighlight = true;
                    this.showLeafCheckedFalseHighlight = true;
                    ths.ShowAlert(ths.$t('NodeAtLeaseLeafNodeMessage'), 'warning', ths.$t('Alert'));
                    return;
                }

                this.showEmptyConditionHighlight = false;
                this.showLeafCheckedFalseHighlight = false;
            } else {
                this.showEmptyConditionHighlight = false;
                this.showLeafCheckedFalseHighlight = false;
            }
            
            var obj = {
                configurationId: this.configurationId,
                rules: []
            };
            this.jsonToSaveRules = [];
            this.rules.forEach(function (rule, index) {
                ths.makeJsonForSave(rule);
            });
            // Ensure there is at least one non-GLOBAL node before saving
            const hasNonGlobalRule = ths.jsonToSaveRules.some(rule => rule.version !== "GLOBAL");
            if (!hasNonGlobalRule) {
                
                ths.ShowAlert(ths.$t("NodeSaveAtleastOneMessage"), "warning", ths.$t("Alert"));
                return;
            }

            const filteredRules = ths.jsonToSaveRules.filter(rule => rule.version !== "GLOBAL");
            obj.rules = filteredRules;
            DataServices.SaveServiceRules(JSON.stringify(obj)).then(function (response) {
                if (response && response.data != null && response.data.status == "Success") {
                    if (obj.rules.length > 0) { 
                        ths.oldConfigId = ths.$route.params.ocId;
                        obj.rules.forEach(item => {
                            let obj = 
                                {
                                    ConnfigurationId: ths.configurationId,
                                    DisplayOrder: item.ruleDisplayOrder,
                                    NodeName: item.version,
                                    ServiceId: item.conditionId,
                                    ClientServiceMappingId: item.parentMappingId,
                                    OriginalConfigId: Number(ths.oldConfigId),
                                    ClientId: ths.clientId,
                                    Type: "TM"
                                };
                                ths.nodeList.push(obj);
                        });
                    }
                    else {
                            ths.ShowAlert(ths.$t('NodeSaveAtleastOneMessage'), 'warning', ths.$t('Alert'));
                        }
                    var saveData = {
                        Nodes: ths.nodeList,
                        IsValidateOverride: true,
                    }
                    DataServices.SaveDisplayOrderNew2(saveData).then(function (response) {
                        if(type == "TM"){
                            if (Number(response.data.status) == 0) {
                                // Mark rules as saved and clear unsaved flag
                                ths.originalRules = JSON.parse(JSON.stringify(ths.rules || []));
                                ths.hasInitialRulesSnapshot = true;
                                ths.$emit("unsaved-state-changed", false);
                                ths.ShowAlert(ths.$t('SuccessfullySaved', [ths.$t('BillingNodeConfiguration')]), "success", true, ths.$t("Alert"));
                                ths.$router.push({ name: 'BillingRule' });
                            }
                            else if(Number(response.data.status) == -2){
                                ths.confirmR(ths.$t("ErrorWhileValidateOverride"), true, (ths.$t("Alert")), function () {
                                    var saveData = {
                                        Nodes: ths.nodeList,
                                        IsValidateOverride: false,
                                    }
                                    DataServices.SaveDisplayOrderNew2(saveData).then(function (response) { 
                                        if (type == "TM") {
                                            // Mark rules as saved and clear unsaved flag
                                            ths.originalRules = JSON.parse(JSON.stringify(ths.rules || []));
                                            ths.hasInitialRulesSnapshot = true;
                                            ths.$emit("unsaved-state-changed", false);
                                            ths.ShowAlert(ths.$t('SuccessfullySaved', [ths.$t('BillingNodeConfiguration')]), "success", true, ths.$t("Alert"));
                                            ths.$router.push({ name: 'BillingRule' });
                                        }
                                    });
                                });
                            }
                            
                        }
                        else {
                            vm.ShowAlert(response.data.msg || "Something went wrong!", "error", true, vm.$t("Alert"));
                        }
                    });
                }
            })
        },
        checkEmptyCondition(rulesArray) {
            for (let i = 0; i < rulesArray.length; i++) {
                let rule = rulesArray[i];
                
                if (!rule.ruleCondition || Object.keys(rule.ruleCondition).length === 0) {
                    return true; 
                }
                
                if (rule.rules && rule.rules.length > 0) {
                    if (this.checkEmptyCondition(rule.rules)) {
                        return true;
                    }
                }
            }
            return false;
        },

        checkLeafCheckedFalse(rulesArray) {
        
            for (let i = 0; i < rulesArray.length; i++) {
                let rule = rulesArray[i];
                
                if (rule.ruleCondition && rule.ruleCondition.isLeafChecked === false) {
                    return true;
                }
                
                if (rule.rules && rule.rules.length > 0) {
                    if (this.checkLeafCheckedFalse(rule.rules)) {
                        return true;
                    }
                }
            }
            return false;
        },
        addMoreRule: function () {
            debugger
            var vm = this;
            var lastRule = vm.rules[vm.rules.length - 1];
            var version = lastRule.version === 'GLOBAL' ? 0 : Number(lastRule.version);
            var newVersion = version + 1;
            vm.rules.push({
                ruleId: 0,
                ruleDisplayOrder: lastRule.ruleDisplayOrder + 1,
                ruleName: "Rule " + newVersion,
                version: newVersion,
                ruleCondition: {},
                rules: [],
                parent: null,
                isDelete: false,
                isShowChild: true,
                hidebuttons: true,
                isUpdateRule: true
            })
            //vm.hasValidationActivity=true;
        },
        // getNodeConfiguration: function () {
        //     let ths = this;
        //     ths.rules = [];
        //     ths.processedData = [];
        //     var prms = `configId=${this.configurationId}`;
        //     DataServices.GetNodeConfigurationData(prms).then(function (res) {
        //         if (res && res.data) {
        //             let dt = res.data;
        //             let data = [];
        //             var filterParentNode = dt.filter((item) => { return item.PARENT_MAPPING_ID == null });
        //               filterParentNode.forEach(function (item, index) {
        //                 if (!ths.processedData.includes(item.CLIENT_SERVICE_MAPPING_ID)) {
        //                     var obj = {
        //                         ruleId: item.CLIENT_SERVICE_MAPPING_ID,
        //                         ruleDisplayOrder: item.DISPLAY_ORDER,
        //                         ruleName: "Rule " + item.DISPLAY_NODE_NAME,
        //                         version: item.DISPLAY_NODE_NAME,
        //                         ruleCondition: {
        //                             conditionId: item.SERVICE_ID,
        //                             serviceName: item.SERVICE_NAME,
        //                             rateCode: "",
        //                             isLeafChecked: item.IS_LEAF_NODE,
        //                             condition: item.CONDITION,
        //                             selectedFlag: {
        //                                 value: "grey",
        //                                 name: "grey"
        //                             },
        //                             nodeName: item.DISPLAY_NODE_NAME,
        //                             dependentOnServices: null,
        //                             dependentPrice: 0,
        //                             dependentType: '',
        //                             functionType: ''

        //                         },
        //                         rules: [],
        //                         parent: null,
        //                         isDelete: false,
        //                         isShowChild: true
        //                     }
        //                     let filteredData = dt.filter((itm) => { return itm.PARENT_MAPPING_ID == item.CLIENT_SERVICE_MAPPING_ID });
        //                     let child = [];
        //                     if (filteredData.length > 0) {
        //                         child = ths.getChildJson(filteredData, dt, item.CLIENT_SERVICE_MAPPING_ID, item.DISPLAY_NODE_NAME);
        //                     }
        //                     obj.rules = child;
        //                     ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
        //                     data.push(obj);
        //                 }
        //             });
        //             ths.rules = data;
        //             if (ths.rules.length == 0) {
        //                 ths.addMoreRule();
        //             }
        //         }
        //     });
        // },
        GetNodeConfigurationData: function () {
            let ths = this;
            ths.rules = [];
            ths.processedData = [];
            if(ths.isBillingType == true){
                var prms = `configId=${this.configurationId}&serviceId=${this.serviceId}&isIncludeGlobalService=true&isView=${this.$route.params.mode}`;
                DataServices.GetNodeConfigurationData(prms).then(function (res) {
                    if (res && res.data) {
                        let dt = res.data;
                        // if (dt && dt.length > 0) {
                        //    this.nodeRuleData = dt;
                          
                        // }
                        let data = [];
                        let globalCounter = 1;
                         // ---------- helper: check if node has children ----------
                        function hasChildren(id) {
                            return dt.some(item => item.PARENT_MAPPING_ID === id);
                        }

                        let rootItems = dt.filter(item => item.PARENT_MAPPING_ID === 0 || item.PARENT_MAPPING_ID === null);

                        // Helper function to create the object
                        function createRuleObject(item, isChild = false) {
                            let childExists = hasChildren(item.CLIENT_SERVICE_MAPPING_ID);
                            return {
                                ruleId: item.CLIENT_SERVICE_MAPPING_ID,
                                ruleDisplayOrder: item.DISPLAY_ORDER,
                                ruleName: item.DISPLAY_NODE_NAME.toUpperCase() === "GLOBAL" ?  `Global ${globalCounter++}`  : "Rule " + item.DISPLAY_NODE_NAME,
                                version: item.DISPLAY_NODE_NAME,
                                // 🎯 STYLE LOGIC
                                styleParent: item.DISPLAY_NODE_NAME.toUpperCase() === "GLOBAL" ? "parentNode1" : isChild
                                    ? "child1"
                                    : childExists
                                        ? "parentNode"
                                        : "parentNode1",
                                ruleCondition: {
                                    conditionId: item.SERVICE_ID,
                                    serviceName: item.SERVICE_NAME,
                                    rateCode: "",
                                    isLeafChecked: item.IS_LEAF_NODE,
                                    condition: item.CONDITION,
                                    parentServiceId: item.PARENT_SERVICE_ID,
                                    parentMappingId: item.PARENT_MAPPING_ID,
                                    selectedFlag: {
                                        value: "grey",
                                        name: "grey"
                                    },
                                    nodeName: item.DISPLAY_NODE_NAME,
                                    dependentOnServices: null,
                                    dependentPrice: 0,
                                    dependentType: '',
                                    functionType: ''
                                },
                                rules: [],
                                parent: item.DISPLAY_NODE_NAME,
                                isDelete: false,
                                isShowChild: true
                            };
                        }

                        // Process root items
                        rootItems.forEach(function (item) {
                            let obj = createRuleObject(item);
                            ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
                            data.push(obj);
                        });

                        // Process other items
                        dt.forEach(function (item) {
                            if (!ths.processedData.includes(item.CLIENT_SERVICE_MAPPING_ID)) {
                                let obj = createRuleObject(item);

                                let filteredData = dt.filter(itm => itm.PARENT_MAPPING_ID == item.CLIENT_SERVICE_MAPPING_ID);
                                if (filteredData.length > 0) {
                                    obj.rules = ths.getChildJson(filteredData, dt, item.CLIENT_SERVICE_MAPPING_ID, item.DISPLAY_NODE_NAME);
                                }

                                ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
                                data.push(obj);
                            }
                        });

                        ths.rules = data;
                        if (ths.rules.length == 0) {
                            ths.addMoreRule();
                        }

                        ths.$nextTick(() => {
                            ths.originalRules = JSON.parse(JSON.stringify(ths.rules || []));
                            ths.hasInitialRulesSnapshot = true;
                            ths.$emit("unsaved-state-changed", false);
                        });
                    }
                });
            }
            else
            {
                var prms = `configId=${this.configurationId}`;
                DataServices.GetNodeConfigurationData(prms).then(function (res) {
                    if (res && res.data) {
                        let dt = res.data;
                        let data = [];
                        var filterParentNode = dt.filter((item) => { return item.PARENT_MAPPING_ID == null });
                        filterParentNode.forEach(function (item, index) {
                            if (!ths.processedData.includes(item.CLIENT_SERVICE_MAPPING_ID)) {
                                var obj = {
                                    ruleId: item.CLIENT_SERVICE_MAPPING_ID,
                                    ruleDisplayOrder: item.DISPLAY_ORDER,
                                    ruleName: "Rule " + item.DISPLAY_NODE_NAME,
                                    version: item.DISPLAY_NODE_NAME,
                                    ruleCondition: {
                                        conditionId: item.SERVICE_ID,
                                        serviceName: item.SERVICE_NAME,
                                        rateCode: "",
                                        isLeafChecked: item.IS_LEAF_NODE,
                                        condition: item.CONDITION,
                                        selectedFlag: {
                                            value: "grey",
                                            name: "grey"
                                        },
                                        nodeName: item.DISPLAY_NODE_NAME,
                                        dependentOnServices: null,
                                        dependentPrice: 0,
                                        dependentType: '',
                                        functionType: ''

                                    },
                                    rules: [],
                                    parent: null,
                                    isDelete: false,
                                    isShowChild: true
                                }
                                let filteredData = dt.filter((itm) => { return itm.PARENT_MAPPING_ID == item.CLIENT_SERVICE_MAPPING_ID });
                                let child = [];
                                if (filteredData.length > 0) {
                                    child = ths.getChildJson(filteredData, dt, item.CLIENT_SERVICE_MAPPING_ID, item.DISPLAY_NODE_NAME);
                                }
                                obj.rules = child;
                                ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
                                data.push(obj);
                            }
                        });
                        ths.rules = data;
                        if (ths.rules.length == 0) {
                            ths.addMoreRule();
                        }

                        ths.$nextTick(() => {
                            ths.originalRules = JSON.parse(JSON.stringify(ths.rules || []));
                            ths.hasInitialRulesSnapshot = true;
                            ths.$emit("unsaved-state-changed", false);
                        });
                    }
                });
            }
            
        },

        getChildJson: function (filterData, dt, clientMappingId, parentNode) {
            let ths = this;
            let returnValue = []
            filterData.forEach(function (item, index) {
                var obj = {
                    ruleId: item.CLIENT_SERVICE_MAPPING_ID,
                    ruleDisplayOrder: item.DISPLAY_ORDER,
                    ruleName: "Rule " + item.DISPLAY_NODE_NAME,
                    version: item.DISPLAY_NODE_NAME,
                    
                    styleParent: "child1",
                    ruleCondition: {
                        conditionId: item.SERVICE_ID,
                        serviceName: item.SERVICE_NAME,
                        parentServiceId: item.PARENT_SERVICE_ID,
                        parentMappingId: item.PARENT_MAPPING_ID,
                        rateCode: "",
                        isLeafChecked: item.IS_LEAF_NODE,
                        condition: item.CONDITION,
                        selectedFlag: {
                            value: "grey",
                            name: "grey"
                        },
                        nodeName: item.DISPLAY_NODE_NAME
                    },
                    rules: [],
                    parent: parentNode,
                    isDelete: false,
                    isShowChild: true
                }
                let filteredData = dt.filter((itm) => { return itm.PARENT_MAPPING_ID == item.CLIENT_SERVICE_MAPPING_ID });
                let child = [];
                if (filteredData.length > 0) {
                    child = ths.getChildJson(filteredData, dt, item.CLIENT_SERVICE_MAPPING_ID, item.DISPLAY_NODE_NAME);
                }
                obj.rules = child;
                ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
                returnValue.push(obj);
            });
            return returnValue;
        }
    },
}

</script>